local LxBaseMgr = require("LApp.Manager.LxBaseMgr")

---@class LxEventMgr:LxBaseMgr
local LxEventMgr = classX("LxEventMgr", LxBaseMgr)

function LxEventMgr:Initialize()
    LxBaseMgr.Initialize(self)

    self._events = {}
    self._firingMap = {}

    self._freeRemoveCaches = {}
    self._freeRemoveCacheLen = 0
end

function LxEventMgr:Dispose()
    local events = self._events
    if events then
        for k, v in pairs(events) do
            events[k] = nil
            for m, n in ipairs(v) do
                n.removed = true
                n.func = nil
                n.target = nil
            end
        end
        self._events = nil
    end
    LxBaseMgr.Dispose(self)
end

function LxEventMgr:ClearAllEvents()
    local events = self._events
    if events then
        for k, v in pairs(events) do
            events[k] = nil
            for m, n in ipairs(v) do
                n.removed = true
                n.func = nil
                n.target = nil
            end
        end
        self._events = {}
    end
end

function LxEventMgr:LogStatus()
    local cnt = 0
    local waitRemoveCnt = 0
    for k,vList in pairs(self._events or {}) do
        for _, v in ipairs(vList) do
            if v.removed then
                waitRemoveCnt = waitRemoveCnt + 1
            else
                cnt = cnt + 1
            end
        end
    end
    LogWarn("event methods  count=" ..cnt .. " , wait remove count=".. waitRemoveCnt)
end

function LxEventMgr:AddEventListener(eventName, method, target)
    local typeEvent = eventName and type(eventName) or nil
    if typeEvent ~= "string" and typeEvent ~= "number" then
        error("event name is valid, need type number, now type is " .. tostring(typeEvent))
    end

    local typeMethod = method and type(method) or nil
    if typeMethod ~= "function" then
        error("event method is valid, need type function, now type is " .. tostring(typeMethod))
    end

    local events = self._events
    local methodList = events[eventName]
    if not methodList then
        methodList = {}
        events[eventName] = methodList
    end
    table.insert(methodList, {func = method, target = target})
end

function LxEventMgr:RemoveEventListener(eventName, method, target)
    local events = self._events
    local methodList = events[eventName]
    if not methodList then return end

    for k = #methodList, 1, -1 do
        local data = methodList[k]
        if data.func == method and data.target == target then
            data.func = nil
            data.target = nil
            data.removed = true
            break
        end
    end
end

function LxEventMgr:GetFreeRemoveCache()
    if self._freeRemoveCacheLen > 0 then
        self._freeRemoveCacheLen = self._freeRemoveCacheLen - 1
        return table.remove(self._freeRemoveCaches)
    end
    return {}
end

function LxEventMgr:AddFreeRemoveCache(removeCache)
    table.insert(self._freeRemoveCaches, removeCache)
    self._freeRemoveCacheLen = self._freeRemoveCacheLen + 1
end

function LxEventMgr:FireEvent(eventName, ...)
    local events = self._events
    local methodList = events[eventName]
    if not methodList then return end

    --避开死循环嵌套
    if self._firingMap[eventName] then
        if LOG_INFO_ENABLED then
            --LogError("不应该进入这里")
            printError("eventMgr", "event is infinite Loop calling, please check the code, event = "..tostring(eventName))
        end
        return
    end

    local removeList = self:GetFreeRemoveCache()
    local removeLen = 0

    local bRemove = true

    self._firingMap[eventName] = true

    local len = #methodList

    for k =1, len do
        local data = methodList[k]
        if data.removed then
            removeLen = removeLen + 1
            removeList[removeLen] = k
            bRemove = true
        else
            if data.target ~= nil then
                xpcallXVar(data.func, data.target, ...)
            else
                xpcallXVar(data.func, ...)
            end

            if self._isDisposed then
                return
            end
        end
    end

    if self._isDisposed then return end

    if bRemove then
        for k = removeLen, 1, -1 do
            table.remove(methodList, removeList[k])
            removeList[k] = nil
        end
    end

    self:AddFreeRemoveCache(removeList)

    self._firingMap[eventName] = nil
end

return LxEventMgr

